// src/components/FormAluno.js
import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';  // importa contexto de auth

function FormAluno({ onNovoAluno, alunoEditando, onFimEdicao }) {
  const { token } = useAuth();  // obtém token JWT

  // Novos estados para avatar
  const [avatarFile, setAvatarFile] = useState(null);
  const [avatarPreview, setAvatarPreview] = useState('');

  // Campos de texto existentes
  const [nome, setNome] = useState('');
  const [ra, setRa] = useState('');
  const [periodoId, setPeriodoId] = useState('');
  const [mensagem, setMensagem] = useState('');

  // Novos campos:
  const [usuario, setUsuario] = useState('');
  const [senha, setSenha] = useState('');
  const [role, setRole] = useState('aluno'); // valor padrão = "aluno"

  // Lista de períodos
  const [periodos, setPeriodos] = useState([]);
  useEffect(() => {
    axios.get('/api/periodos')
      .then(res => setPeriodos(res.data))
      .catch(() => setPeriodos([]));
  }, []);

  // Carrega dados ao editar, incluindo avatar
  useEffect(() => {
    if (alunoEditando) {
      setNome(alunoEditando.nome || '');
      setRa(alunoEditando.ra || '');
      setPeriodoId(
        alunoEditando.periodo_id != null ? String(alunoEditando.periodo_id) : ''
      );
      setUsuario(alunoEditando.usuario || '');
      setRole(alunoEditando.role || 'aluno');
      setSenha('');
      setAvatarPreview(alunoEditando.avatar_url || '');
      setAvatarFile(null);
    } else {
      setNome('');
      setRa('');
      setPeriodoId('');
      setUsuario('');
      setSenha('');
      setRole('aluno');
      setAvatarPreview('');
      setAvatarFile(null);
    }
    setMensagem('');
  }, [alunoEditando]);

  // Validadores
  function validarNomeCompleto(nome) {
    const partes = nome.trim().split(' ').filter(p => p.length >= 2);
    return partes.length >= 2;
  }
  function validarRA(ra) {
    return /^\d{1,9}$/.test(ra);
  }

  // Handler do avatar
  const handleAvatarChange = e => {
    const file = e.target.files[0];
    if (file) {
      setAvatarFile(file);
      setAvatarPreview(URL.createObjectURL(file));
    }
  };

  // Submit deve ser async para await upload
  const handleSubmit = async e => {
    e.preventDefault();
    setMensagem('');

    // Validações
    if (!validarNomeCompleto(nome)) {
      setMensagem('Informe o nome completo!');
      return;
    }
    if (!validarRA(ra)) {
      setMensagem('O RA deve conter apenas números e até 9 dígitos!');
      return;
    }
    if (!usuario.trim()) {
      setMensagem('Insira um usuário para login!');
      return;
    }
    if (!alunoEditando && senha.length < 4) {
      setMensagem('Senha deve ter no mínimo 4 caracteres!');
      return;
    }
    if (!periodoId) {
      setMensagem('Selecione um período!');
      return;
    }

    // Monta payload base
    const dadosBase = {
      nome,
      ra,
      periodo_id: periodoId,
      usuario,
      role
    };

    try {
      let alunoId;
      if (alunoEditando) {
        // editar
        const payload = { ...dadosBase };
        if (senha) payload.senha = senha;
        await axios.put(`/api/alunos/${alunoEditando.id}`, payload, {
          headers: { Authorization: `Bearer ${token}` }
        });
        alunoId = alunoEditando.id;
        setMensagem('Aluno atualizado com sucesso!');
      } else {
        // criar
        const payload = { ...dadosBase, senha };
        const res = await axios.post('/api/alunos', payload, {
          headers: { Authorization: `Bearer ${token}` }
        });
        alunoId = res.data.id;
        setMensagem('Aluno cadastrado com sucesso!');
      }

      // upload de avatar, se selecionado
      if (avatarFile) {
        const form = new FormData();
        form.append('avatar', avatarFile);
        await axios.post(
          '/api/alunos/avatar',
          form,
          {
            headers: {
              'Content-Type': 'multipart/form-data',
              Authorization: `Bearer ${token}`
            },
            withCredentials: true
          }
        );
      }

      // reset campos e callbacks
      setNome(''); setRa(''); setPeriodoId('');
      setUsuario(''); setSenha(''); setRole('aluno');
      setAvatarPreview(''); setAvatarFile(null);
      onNovoAluno();
      if (alunoEditando) onFimEdicao(); else setTimeout(() => { onFimEdicao && onFimEdicao(); setMensagem(''); }, 1500);
    } catch (err) {
      setMensagem(err.response?.data?.error || 'Erro ao salvar aluno.');
    }
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-4">
      <h2 className="text-xl font-bold">
        {alunoEditando ? 'Editar Aluno' : 'Cadastrar Novo Aluno'}
      </h2>

      {/* Avatar */}
      <div>
        <label className="block font-medium mb-1">Avatar:</label>
        <input
          type="file"
          accept="image/*"
          onChange={handleAvatarChange}
        />
        {avatarPreview && (
          <img
            src={avatarPreview}
            alt="Preview do avatar"
            className="w-24 h-24 rounded-full object-cover mt-2"
          />
        )}
      </div>

      {/* Nome Completo */}
      <div>
        <label className="block font-medium mb-1">Nome Completo:</label>
        <input
          type="text"
          className="w-full border rounded px-3 py-2"
          value={nome}
          onChange={e => setNome(e.target.value)}
          required
        />
      </div>

      {/* RA */}
      <div>
        <label className="block font-medium mb-1">RA:</label>
        <input
          type="text"
          className="w-full border rounded px-3 py-2"
          value={ra}
          onChange={e => setRa(e.target.value.replace(/\D/g, '').slice(0, 9))}
          maxLength={9}
          required
        />
      </div>

      {/* Período */}
      <div>
        <label className="block font-medium mb-1">Período:</label>
        <select
          className="w-full border rounded px-3 py-2"
          value={periodoId}
          onChange={e => setPeriodoId(e.target.value)}
          required
        >
          <option value="">Selecione um período</option>
          {periodos.map(p => (
            <option key={p.id} value={String(p.id)}>
              {p.nome} ({p.turno})
            </option>
          ))}
        </select>
      </div>

      {/* Usuário */}
      <div>
        <label className="block font-medium mb-1">Login:</label>
        <input
          type="text"
          className="w-full border rounded px-3 py-2"
          placeholder="Exemplo: Número do seu RA"
          value={usuario}
          onChange={e => setUsuario(e.target.value)}
          required
        />
      </div>

      {/* Senha */}
      <div>
        <label className="block font-medium mb-1">
          {alunoEditando ? 'Nova senha (deixe em branco para manter)' : 'Senha:'}
        </label>
        <input
          type="password"
          className="w-full border rounded px-3 py-2"
          placeholder="••••••••"
          value={senha}
          onChange={e => setSenha(e.target.value)}
          required={!alunoEditando}
        />
      </div>

      {/* Role */}
      <div>
        <label className="block font-medium mb-1">Permissão:</label>
        <select
          className="w-full border rounded px-3 py-2"
          value={role}
          onChange={e => setRole(e.target.value)}
        >
          <option value="aluno">Aluno</option>
          <option value="recepcao">Recepção</option>
        </select>
      </div>

      {/* Botões */}
      <div className="flex items-center gap-4 mt-4">
        <button
          type="submit"
          className="bg-[#1A1C2C] text-white font-semibold py-2 px-6 rounded-full hover:bg-[#3B4854]"
        >
          {alunoEditando ? 'Atualizar' : 'Cadastrar'}
        </button>
        {alunoEditando && (
          <button
            type="button"
            className="bg-[#DA3648] text-white font-semibold py-2 px-6 rounded-full hover:bg-[#BC3140]"
            onClick={onFimEdicao}
          >
            Cancelar
          </button>
        )}
      </div>

      {mensagem && (
        <p
          className={`mt-2 ${
            mensagem.toLowerCase().includes('sucesso')
              ? 'text-green-600'
              : 'text-red-600'
          }`}
        >
          {mensagem}
        </p>
      )}
    </form>
  );
}

export default FormAluno;
